Action.Str:
var devices = [];
// Tasker-arrays börjar på 1, JS på 0.
// bt_address.length ger antal hittade enheter.
for (var i = 0; i < bt_address.length; i++) {
    devices.push({
        mac: bt_address[i],
        name: bt_name[i],
        rssi: parseInt(bt_signal_strength[i])
    });
}
var payload = JSON.stringify({browser_id: "[YOUR_DEVICE_ID]", devices: devices });
